class Solution(object):
    def isLongPressedName(self, name, typed):
        name_idx = 0
        for char in typed:
            if name_idx < len(name) and name[name_idx] == char:
                name_idx += 1
            elif not name_idx or name[name_idx - 1] != char:
                return False
        return name_idx == len(name)
